const fs = require\('fs'\);
const code = fs.readFileSync\('server.js', 'utf8'\);
// Check for common issues
const lines = code.split\('\\n'\);
let braceCount = 0;
let parenCount = 0;
for \(let i = 0; i < lines.length; i++\) {
  for \(const ch of lines[i]\) {
    if \(ch === '{'\) braceCount++;
    if \(ch === '}'\) braceCount--;
    if \(ch === '\('\) parenCount++;
    if \(ch === '\)'\) parenCount--;
  }
}
console.log\('Final brace balance:', braceCount\);
console.log\('Final paren balance:', parenCount\);
console.log\('Total lines:', lines.length\);
")

Bash(node -e "
const fs = require\('fs'\);
const code = fs.readFileSync\('server.js', 'utf8'\);
// Look for any non-ASCII characters outside of string literals
const lines = code.split\('\\n'\);
for \(let i = 0; i < lines.length; i++\) {
  const line = lines[i];
  for \(let j = 0; j < line.length; j++\) {
    const c = line.charCodeAt\(j\);
    if \(c > 127 && c !== 8211\) { // 8211 is en-dash used in slot strings
      console.log\('Line ' + \(i+1\) + ' col ' + \(j+1\) + ': char code ' + c + ' char: ' + line[j]\);
    }
  }
}
console.log\('Done checking'\);
")

