Bash(node -e "
const fs = require\('fs'\);
const code = fs.readFileSync\('server.js', 'utf8'\);
const lines = code.split\('\\n'\);
let depth = 0;
for \(let i = 0; i < lines.length; i++\) {
  const line = lines[i];
  // Track depth roughly
  for \(const ch of line\) {
    if \(ch === '{'\) depth++;
    if \(ch === '}'\) depth--;
  }
  // Show lines at depth 0 that are actual statements \(not comments, not blank\)
  if \(depth <= 0 && line.trim\(\) && !line.trim\(\).startsWith\('//'\) && !line.trim\(\).startsWith\('/*'\) && !line.trim\(\).startsWith\('*'\)\) {
    // Filter to show potentially crashing lines
    if \(line.includes\('JSON.parse'\) || line.includes\('require'\) || line.includes\('throw'\) || line.includes\('new '\)\) {
      console.log\(\(i+1\) + ': ' + line.trim\(\)\);
    }
  }
}
")

